// src/components/courses/CourseDetail.js
import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { coursesService } from '../../services/courses';
import { enrollmentsService } from '../../services/enrollments';
import { authService } from '../../services/auth';
import api from '../../services/api';
import PaymentModal from '../payment/PaymentModal';
import './CourseDetail.css';

// ─── Video Player ─────────────────────────────────────────────────────────────
const VideoPlayer = ({ lecture }) => {
  const [streamUrl, setStreamUrl] = useState('');
  const [loadingUrl, setLoadingUrl] = useState(false);

  const getEmbedUrl = (url) => {
    if (!url) return null;
    const ytMatch = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([^&\s]+)/);
    if (ytMatch) return `https://www.youtube.com/embed/${ytMatch[1]}`;
    const vmMatch = url.match(/vimeo\.com\/(\d+)/);
    if (vmMatch) return `https://player.vimeo.com/video/${vmMatch[1]}`;
    return null;
  };

  useEffect(() => {
    if (lecture?.video_type === 'upload' && lecture?.s3_key) {
      setLoadingUrl(true);
      api.get(`/courses/lectures/${lecture.id}/stream/`)
        .then((res) => setStreamUrl(res.data.stream_url))
        .catch(console.error)
        .finally(() => setLoadingUrl(false));
    }
  }, [lecture?.id]);

  if (!lecture) return null;

  if (lecture.video_type === 'upload') {
    if (loadingUrl) return <div style={vp.box}>⏳ جاري تحميل الفيديو...</div>;
    if (!streamUrl) return <div style={vp.box}>❌ تعذّر تحميل الفيديو</div>;
    return (
      <video style={vp.video} controls controlsList="nodownload">
        <source src={streamUrl} />
        المتصفح لا يدعم تشغيل الفيديو.
      </video>
    );
  }

  const embedUrl = getEmbedUrl(lecture.video_url);
  if (!embedUrl) return <div style={vp.box}>❌ رابط فيديو غير صالح</div>;
  return (
    <iframe style={vp.iframe} src={embedUrl} title={lecture.title}
      allowFullScreen allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" />
  );
};

const vp = {
  video: { width:'100%', borderRadius:8, background:'#000', maxHeight:420 },
  iframe:{ width:'100%', height:420, border:'none', borderRadius:8 },
  box:   { padding:40, textAlign:'center', color:'#666', background:'#f8f9fa', borderRadius:8 },
};

// ─── Main Component ───────────────────────────────────────────────────────────
const CourseDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();

  const [course, setCourse]           = useState(null);
  const [loading, setLoading]         = useState(true);
  const [error, setError]             = useState('');
  const [isEnrolled, setIsEnrolled]   = useState(false);
  const [enrolling, setEnrolling]     = useState(false);
  const [showPayment, setShowPayment] = useState(false);
  const [activeLecture, setActiveLecture] = useState(null);
  const [openSections, setOpenSections]   = useState({});

  const user         = JSON.parse(localStorage.getItem('user'));
  const isAdmin      = user?.is_staff;
  const isInstructor = user?.is_instructor;
  const isOwner      = isInstructor && course?.instructor === user?.id;
  const canSeeContent = isEnrolled || isAdmin || isOwner;

  useEffect(() => { loadCourse(); checkEnrollment(); }, [id]);

  const loadCourse = async () => {
    try {
      setLoading(true);
      const data = await coursesService.getById(id);
      setCourse(data);
      if (data.sections?.length) setOpenSections({ [data.sections[0].id]: true });
    } catch { setError('Failed to load course'); }
    finally { setLoading(false); }
  };

  const checkEnrollment = async () => {
    if (!authService.isAuthenticated()) return;
    try {
      const enrolled = await enrollmentsService.checkEnrollment(id);
      setIsEnrolled(enrolled);
    } catch {}
  };

  const handleEnrollFree = async () => {
    if (!authService.isAuthenticated()) { navigate('/login'); return; }
    try {
      setEnrolling(true);
      await enrollmentsService.enroll(id);
      setIsEnrolled(true);
      await loadCourse();
    } catch (err) {
      alert(err.response?.data?.non_field_errors?.[0] || 'فشل الإلتحاق');
    } finally { setEnrolling(false); }
  };

  const handlePaymentSuccess = async () => {
    setShowPayment(false);
    setIsEnrolled(true);
    await loadCourse();
  };

  const toggleSection = (sId) =>
    setOpenSections((prev) => ({ ...prev, [sId]: !prev[sId] }));

  const selectLecture = (lecture, locked) => {
    if (locked) return;
    setActiveLecture(lecture);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  if (loading) return <div className="loading">Loading course...</div>;
  if (error || !course) return <div className="error-message">{error || 'Course not found'}</div>;

  const isPaid = parseFloat(course.price) > 0;

  return (
    <div className="course-detail">

      {/* ── Active Video Player ── */}
      {activeLecture && canSeeContent && (
        <div style={css.playerWrap}>
          <div style={css.playerInner}>
            <h3 style={{ marginBottom:10, color:'#fff' }}>▶ {activeLecture.title}</h3>
            <VideoPlayer lecture={activeLecture} />
          </div>
        </div>
      )}

      {/* ── Header ── */}
      <div className="course-header">
        <div className="course-image-large">
          {course.image_url
            ? <img src={course.image_url} alt={course.title} />
            : <div className="course-image-placeholder-large">No Image</div>}
        </div>
        <div className="course-header-info">
          <h1>{course.title}</h1>
          <p className="course-instructor">Instructor: {course.instructor_name || course.instructor_email}</p>
          <p className="course-description">{course.description}</p>
          <div className="course-stats">
            <span>📂 {course.total_sections} Sections</span>
            <span>🎬 {course.total_lectures} Lectures</span>
          </div>
          <div className="course-actions">
            <span className="course-price-large">
              {isPaid ? `${parseFloat(course.price).toFixed(2)} EGP` : 'مجاني'}
            </span>

            {canSeeContent ? (
              <button className="btn btn-success"
                onClick={() => document.getElementById('course-content')?.scrollIntoView({ behavior:'smooth' })}>
                ▶ ابدأ التعلم
              </button>
            ) : isPaid ? (
              <button className="btn btn-primary"
                onClick={() => { if (!authService.isAuthenticated()) { navigate('/login'); return; } setShowPayment(true); }}>
                💳 اشتري الكورس – {parseFloat(course.price).toFixed(2)} EGP
              </button>
            ) : (
              <button className="btn btn-primary" disabled={enrolling} onClick={handleEnrollFree}>
                {enrolling ? 'جاري التسجيل...' : 'سجّل مجاناً'}
              </button>
            )}
          </div>
        </div>
      </div>

      {/* ── Sections & Lectures ── */}
      {course.sections && course.sections.length > 0 && (
        <div id="course-content" className="course-content">
          <h2>Course Content</h2>

          {!canSeeContent && (
            <div className="enrollment-notice">
              <p>{isPaid ? '🔒 اشتري الكورس للوصول للمحتوى' : '🔒 سجّل مجاناً للوصول للمحتوى'}</p>
            </div>
          )}

          {course.sections.map((section) => (
            <div key={section.id} style={css.sectionBox}>
              {/* Clickable header */}
              <div style={css.sectionHeader} onClick={() => toggleSection(section.id)}>
                <span>{openSections[section.id] ? '▾' : '▸'} {section.title}</span>
                <span style={css.sectionMeta}>{section.lectures?.length || 0} ليكتشر</span>
              </div>

              {/* Lectures */}
              {openSections[section.id] && (
                <ul style={css.lectureList}>
                  {section.lectures?.map((lecture) => {
                    const isActive = activeLecture?.id === lecture.id;
                    const isFree   = lecture.is_free_preview;
                    const locked   = !canSeeContent && !isFree;
                    return (
                      <li key={lecture.id} style={css.lectureItem(isActive, locked)}
                        onClick={() => selectLecture(lecture, locked)}>
                        <span style={css.lIcon}>
                          {locked ? '🔒' : lecture.video_type !== 'upload' ? '▶' : '🎬'}
                        </span>
                        <span style={{ flex:1 }}>{lecture.title}</span>
                        {isFree && !canSeeContent && <span style={css.freeBadge}>مجاني</span>}
                        {lecture.duration_minutes > 0 && (
                          <span style={css.duration}>{lecture.duration_minutes} د</span>
                        )}
                      </li>
                    );
                  })}
                </ul>
              )}
            </div>
          ))}
        </div>
      )}

      {/* ── Payment Modal ── */}
      {showPayment && (
        <PaymentModal course={course} onSuccess={handlePaymentSuccess} onClose={() => setShowPayment(false)} />
      )}
    </div>
  );
};

const css = {
  playerWrap:  { background:'#1a1a2e', padding:'20px 0' },
  playerInner: { maxWidth:860, margin:'0 auto', padding:'0 20px' },
  sectionBox:  { border:'1px solid #e0e0e0', borderRadius:8, marginBottom:10, overflow:'hidden' },
  sectionHeader:{ display:'flex', justifyContent:'space-between', alignItems:'center',
                  padding:'12px 16px', background:'#f0f4ff', cursor:'pointer',
                  userSelect:'none', fontWeight:600 },
  sectionMeta: { fontSize:13, color:'#666', fontWeight:400 },
  lectureList: { margin:0, padding:0, listStyle:'none' },
  lectureItem: (active, locked) => ({
    display:'flex', alignItems:'center', gap:10, padding:'10px 16px',
    cursor: locked ? 'not-allowed' : 'pointer',
    background: active ? '#e8f4fd' : 'transparent',
    borderTop:'1px solid #f0f0f0',
    opacity: locked ? 0.55 : 1,
  }),
  lIcon:      { fontSize:16, minWidth:22 },
  freeBadge:  { fontSize:11, background:'#d4edda', color:'#155724', borderRadius:8, padding:'2px 8px', fontWeight:600 },
  duration:   { color:'#999', fontSize:12 },
};

export default CourseDetail;
